// src/components/ProductCard.jsx
import { useState } from 'react';
import { useCart } from '../context/CartContext';
import { motion } from 'framer-motion';

const ProductCard = ({ product }) => {
  const [selectedSize, setSelectedSize] = useState(null);
  const { addToCart } = useCart();

  const handleAddToCart = () => {
    if (!selectedSize) {
      alert("Please select a size");
      return;
    }
    addToCart(product, selectedSize);
    setSelectedSize(null);

    const notif = document.createElement('div');
    notif.className = "fixed bottom-8 left-1/2 -translate-x-1/2 bg-[#d4af37] text-[#0a0a1f] px-8 py-4 rounded-2xl shadow-2xl z-[2000] font-medium";
    notif.textContent = `${product.name} (${selectedSize}) added`;
    document.body.appendChild(notif);
    setTimeout(() => notif.remove(), 2200);
  };

  return (
    <motion.div 
      whileHover={{ y: -20, rotateX: 8, rotateY: 8 }}
      transition={{ type: "spring", stiffness: 400 }}
      className="bg-white rounded-3xl overflow-hidden shadow-2xl group"
    >
      <div className="relative h-80 overflow-hidden bg-gradient-to-br from-gray-50 to-gray-100">
        <motion.img 
          src={product.image} 
          alt={product.name}
          className="w-full h-full object-cover"
          whileHover={{ scale: 1.12 }}
          transition={{ duration: 0.8 }}
        />
      </div>

      <div className="p-8">
        <h3 className="font-serif text-3xl text-[#0a0a1f]">{product.name}</h3>
        <p className="text-[#d4af37] text-3xl font-semibold mt-2">Rs. {product.price}</p>

        <div className="mt-8">
          <p className="uppercase text-xs tracking-widest text-gray-500 mb-4">Select Size (UK)</p>
          <div className="flex flex-wrap gap-3">
            {product.sizes.map(size => (
              <button
                key={size}
                onClick={() => setSelectedSize(size)}
                className={`w-12 h-12 rounded-2xl border transition-all text-sm font-medium ${
                  selectedSize === size 
                    ? 'bg-[#0a0a1f] text-white' 
                    : 'hover:border-[#d4af37]'
                }`}
              >
                {size}
              </button>
            ))}
          </div>
        </div>

        <motion.button
          whileHover={{ scale: 1.03 }}
          whileTap={{ scale: 0.97 }}
          onClick={handleAddToCart}
          className="mt-10 w-full bg-[#0a0a1f] hover:bg-[#d4af37] hover:text-[#0a0a1f] py-5 rounded-2xl text-lg font-medium transition-all"
        >
          ADD TO CART
        </motion.button>
      </div>
    </motion.div>
  );
};

export default ProductCard;