// src/components/Hero.jsx
import { motion } from 'framer-motion';

const Hero = () => {
  return (
    <section className="relative min-h-screen bg-[#0a0a1f] overflow-hidden flex items-center">
      {/* Background gradient */}
      <div className="absolute inset-0 bg-gradient-to-br from-[#0a0a1f] via-[#1a1a2e] to-[#0a0a1f]" />

      <div className="max-w-7xl mx-auto px-8 relative z-10">
        <div className="max-w-3xl">
          <motion.h1 
            initial={{ opacity: 0, y: 60 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 1, ease: "easeOut" }}
            className="text-7xl md:text-8xl font-serif tracking-tight leading-none text-white mb-6"
          >
            Timeless<br />
            <span className="text-[#d4af37]">Leathercraft</span>
          </motion.h1>

          <motion.p 
            initial={{ opacity: 0, y: 40 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.3 }}
            className="text-2xl text-gray-300 mb-12 max-w-lg"
          >
            Handcrafted in Sialkot with passion.<br />
            Half sizes. Premium fit.
          </motion.p>

          <motion.div 
            initial={{ opacity: 0, y: 50 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.6 }}
          >
            <a href="#shop" 
               className="inline-block bg-[#d4af37] text-[#0a0a1f] px-12 py-5 rounded-2xl text-xl font-medium hover:bg-amber-300 transition">
              Explore Collection
            </a>
          </motion.div>
        </div>
      </div>

      {/* Floating 3D Shoe */}
      <motion.div 
        animate={{ 
          y: [0, -30, 0],
          rotate: [0, 8, -8, 0]
        }}
        transition={{ duration: 8, repeat: Infinity, ease: "easeInOut" }}
        className="absolute bottom-10 right-10 hidden lg:block text-[280px] opacity-10"
      >
        👟
      </motion.div>
    </section>
  );
};

export default Hero;