import { useState } from 'react';
import { Menu, X, ShoppingBag, ChevronDown } from 'lucide-react';
import { useCart } from '../context/CartContext';
import { Link } from 'react-router-dom';
import { motion } from 'framer-motion';

const Navbar = () => {
  const [isMobileOpen, setIsMobileOpen] = useState(false);
  const [isCategoriesOpen, setIsCategoriesOpen] = useState(false);
  const { totalItems } = useCart();

  const categories = [
    { name: "Formal Shoes", path: "/shop?category=formal" },
    { name: "Wedding Shoes", path: "/shop?category=wedding" },
    { name: "Casual Shoes", path: "/shop?category=casual" },
    { name: "Boots", path: "/shop?category=boots" },
  ];

  return (
    <motion.nav 
      initial={{ y: -80, opacity: 0 }}
      animate={{ y: 0, opacity: 1 }}
      transition={{ duration: 0.6, ease: "easeOut" }}
      className="bg-[#0a0a1f] text-white sticky top-0 z-50 border-b border-[#d4af37]/10"
    >
      <div className="max-w-7xl mx-auto px-8 py-6 flex justify-between items-center">
        
        {/* Logo */}
        <Link to="/" className="group">
          <motion.div 
            whileHover={{ scale: 1.05 }}
            className="text-4xl font-serif tracking-[5px] text-[#d4af37] group-hover:text-amber-300 transition-colors"
          >
            VELUM
          </motion.div>
        </Link>

        {/* Desktop Menu */}
        <div className="hidden md:flex items-center gap-12 text-sm uppercase tracking-widest font-medium">
          <Link to="/" className="hover:text-[#d4af37] transition">Home</Link>

          <div className="relative">
            <button 
              onClick={() => setIsCategoriesOpen(!isCategoriesOpen)}
              className="flex items-center gap-2 hover:text-[#d4af37] transition"
            >
              CATEGORIES
              <motion.span animate={{ rotate: isCategoriesOpen ? 180 : 0 }}>
                <ChevronDown size={18} />
              </motion.span>
            </button>

            {isCategoriesOpen && (
              <motion.div 
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                className="absolute top-full left-1/2 -translate-x-1/2 mt-5 w-72 bg-white text-[#0a0a1f] rounded-3xl shadow-2xl py-6 z-50"
              >
                <div className="px-8 space-y-4">
                  {categories.map((cat) => (
                    <Link
                      key={cat.name}
                      to={cat.path}
                      className="block py-3 text-lg hover:text-[#d4af37] transition"
                      onClick={() => setIsCategoriesOpen(false)}
                    >
                      {cat.name}
                    </Link>
                  ))}
                </div>
              </motion.div>
            )}
          </div>

          <Link to="/about" className="hover:text-[#d4af37] transition">About</Link>
        </div>

        {/* Cart */}
        <Link to="/cart" className="flex items-center gap-3 group">
          <div className="text-sm font-medium tracking-wider group-hover:text-[#d4af37]">CART</div>
          <motion.div whileHover={{ scale: 1.1 }} className="relative">
            <ShoppingBag size={26} className="group-hover:text-[#d4af37]" />
            {totalItems > 0 && (
              <motion.span 
                initial={{ scale: 0 }} 
                animate={{ scale: 1 }}
                className="absolute -top-2 -right-2 bg-[#d4af37] text-[#0a0a1f] text-xs font-bold w-6 h-6 rounded-full flex items-center justify-center"
              >
                {totalItems}
              </motion.span>
            )}
          </motion.div>
        </Link>

        {/* Mobile Button */}
        <button onClick={() => setIsMobileOpen(!isMobileOpen)} className="md:hidden">
          {isMobileOpen ? <X size={28} /> : <Menu size={28} />}
        </button>
      </div>

      {/* Mobile Menu */}
      {isMobileOpen && (
        <motion.div 
          initial={{ opacity: 0, height: 0 }}
          animate={{ opacity: 1, height: 'auto' }}
          className="md:hidden bg-[#0a0a1f] px-8 py-8"
        >
          <div className="flex flex-col gap-6 text-lg">
            <Link to="/" onClick={() => setIsMobileOpen(false)}>Home</Link>
            <div>
              <p className="text-[#d4af37] mb-4">CATEGORIES</p>
              {categories.map(cat => (
                <Link key={cat.name} to={cat.path} onClick={() => setIsMobileOpen(false)} className="block py-3">
                  {cat.name}
                </Link>
              ))}
            </div>
            <Link to="/about" onClick={() => setIsMobileOpen(false)}>About</Link>
          </div>
        </motion.div>
      )}
    </motion.nav>
  );
};

export default Navbar;