// src/components/Footer.jsx
import { Link } from 'react-router-dom';

const Footer = () => {
  return (
    <footer className="bg-[#0a0a1f] text-gray-400 pt-20 pb-12">
      <div className="max-w-7xl mx-auto px-8">
        <div className="grid md:grid-cols-12 gap-12">
          <div className="md:col-span-5">
            <div className="text-5xl font-serif text-[#d4af37] mb-6">VELUM</div>
            <p className="text-lg max-w-md">
              Where heritage meets craftsmanship. Premium leather shoes made in Sialkot with passion and precision.
            </p>
          </div>

          <div className="md:col-span-3">
            <h4 className="text-white uppercase tracking-widest text-sm mb-6">Navigate</h4>
            <div className="space-y-3">
              <Link to="/" className="block hover:text-white">Home</Link>
              <Link to="/shop" className="block hover:text-white">Shop</Link>
              <Link to="/size-guide" className="block hover:text-white">Size Guide</Link>
              <Link to="/about" className="block hover:text-white">Our Story</Link>
            </div>
          </div>

          <div className="md:col-span-4">
            <h4 className="text-white uppercase tracking-widest text-sm mb-6">Collections</h4>
            <div className="grid grid-cols-2 gap-y-3 text-sm">
              <Link to="/shop?category=formal" className="hover:text-white">Formal</Link>
              <Link to="/shop?category=wedding" className="hover:text-white">Wedding</Link>
              <Link to="/shop?category=casual" className="hover:text-white">Casual</Link>
              <Link to="/shop?category=boots" className="hover:text-white">Boots</Link>
            </div>
          </div>
        </div>

        <div className="text-center text-xs mt-20 pt-8 border-t border-gray-800">
          © 2026 Velum • Handcrafted with pride in Sialkot, Pakistan
        </div>
      </div>
    </footer>
  );
};

export default Footer;